<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <title>2048 Game</title>
    <style>
        :root {
            --bg-color: #333;
            --board-bg: #444;
            --tile-bg: #eee;
            --text-color: #fff;
            --accent-color: #2196F3;
        }

        body {
            font-family: 'Segoe UI', Tahoma, Geneva, Verdana, sans-serif;
            background-color: var(--bg-color);
            color: var(--text-color);
            display: flex;
            justify-content: center;
            align-items: center;
            height: 100vh;
            margin: 0;
        }

        #game-container {
            display: flex;
            flex-direction: column;
            align-items: center;
            gap: 10px;
        }

        header {
            display: flex;
            justify-content: space-between;
            width: 350px;
            margin-bottom: 10px;
        }

        #score-box {
            background-color: var(--board-bg);
            padding: 10px 20px;
            border-radius: 5px;
            font-size: 1.2rem;
            text-align: center;
            min-width: 80px;
        }

        #score {
            font-weight: bold;
            color: var(--accent-color);
        }

        button#reset {
            background-color: var(--accent-color);
            border: none;
            color: white;
            padding: 10px 20px;
            border-radius: 5px;
            cursor: pointer;
            font-size: 1rem;
        }

        button#reset:hover {
            opacity: 0.9;
        }

        #board {
            display: grid;
            grid-template-columns: repeat(4, 1fr);
            gap: 10px;
            background-color: var(--board-bg);
            padding: 10px;
            border-radius: 5px;
            width: 350px;
            height: 350px;
        }

        .tile {
            background-color: #666; /* Empty cell color */
            border-radius: 4px;
            display: flex;
            justify-content: center;
            align-items: center;
            font-size: 2rem;
            font-weight: bold;
            color: #fff;
            transition: transform 0.1s ease-in-out;
        }

        /* Tile colors based on value */
        .tile[data-val="2"] { background-color: #eee4da; color: #776e65; }
        .tile[data-val="4"] { background-color: #ede0c8; color: #776e65; }
        .tile[data-val="8"] { background-color: #f2b179; color: #f9f6f2; }
        .tile[data-val="16"] { background-color: #f59563; color: #f9f6f2; }
        .tile[data-val="32"] { background-color: #f67c5f; color: #f9f6f2; }
        .tile[data-val="64"] { background-color: #f65e3b; color: #f9f6f2; }
