        .tile[data-val="2048"] { background-color: #edc22e; color: #f9f6f2; font-size: 1.5rem;}

    </style>
</head>
<body>

<div id="game-container">
    <header>
        <div id="score-box">Score: <span id="score">0</span></div>
        <button id="reset">New Game</button>
    </header>
    <div id="board"></div>
</div>

<script>
(function() {
    // Internal State
    let boardState = []; // 4x4 array
    let score = 0;
    const SIZE = 4;

    // DOM Elements
    const boardEl = document.getElementById('board');
    const scoreEl = document.getElementById('score');
    const resetBtn = document.getElementById('reset');

    // Initialize Game
    function init() {
        window.game = {
            size: SIZE,
            reset: resetGame,
            move: handleMove,
            board: getBoard,
            setBoard: setBoard,
            score: getScore
        };

        resetBtn.addEventListener('click', resetGame);
        document.addEventListener('keydown', handleInput);
    }

    function resetGame() {
        // Create empty 4x4 grid
        boardState = Array(SIZE).fill(null).map(() => Array(SIZE).fill(0));
        score = 0;

        // Spawn two tiles
        spawnTile();
        spawnTile();

        updateUI();
    }

    function getBoard() {
        return boardState.map(row => [...row]); // Return a copy to prevent external mutation issues if needed, though setBoard handles direct assignment.
    }

    function getScore() {
        return score;
    }

    function setBoard(arr) {
        // Deep copy the array provided by grading script
        boardState = arr.map(row => [...row]);
        updateUI();
    }

    function spawnTile() {
        const emptyCells = [];
        for (let r = 0; r < SIZE; r++) {
            for (let c = 0; c < SIZE; c++) {
                if (boardState[r][c] === 0) {
                    emptyCells.push({r, c});
                }
            }
        }

        if (emptyCells.length > 0) {
            const randomCell = emptyCells[Math.floor(Math.random() * emptyCells.length)];
            // 90% chance of 2, 10% chance of 4
            boardState[randomCell.r][randomCell.c] = Math.random() < 0.9 ? 2 : 4;
        }
    }

    function updateUI() {
        scoreEl.textContent = score;
        boardEl.innerHTML = ''; // Clear board

        for (let r = 0; r < SIZE; r++) {
            for (let c = 0; c < SIZE; c++) {
                const tile = document.createElement('div');
                const val = boardState[r][c];

                if (val !== 0) {
                    tile.textContent = val;
                    tile.classList.add('tile');
                    tile.setAttribute('data-val', val);
                } else {
                    // Empty cell styling handled by CSS default, but let's ensure it looks right
                    tile.style.visibility = 'hidden'; 
                }

                boardEl.appendChild(tile);
            }
        }
    }

    function handleInput(e) {
        if (['ArrowUp', 'ArrowDown', 'ArrowLeft', 'ArrowRight'].includes(e.key)) {
            e.preventDefault(); // Prevent scrolling
            const dir = getDirectionFromKey(e.key);
            if (dir) {
                const moved = window.game.move(dir);
                if (moved) {
                    spawnTile();
                    updateUI();
                }
            }
        }
    }

    function getDirectionFromKey(key) {
        switch(key) {
            case 'ArrowLeft': return 'left';
            case 'ArrowRight': return 'right';
            case 'ArrowUp': return 'up';
            case 'ArrowDown': return 'down';
            default: return null;
        }
    }

    // Core Logic
    function handleMove(direction) {
        let moved = false;

        // Helper to process a single row/col as if moving left
        const slideAndMerge = (line) => {
            // 1. Remove zeros
            let filtered = line.filter(val => val !== 0);

            // 2. Merge
            let merged = [];
            for (let i = 0; i < filtered.length; i++) {
                if (merged.length > 0 && merged[merged.length - 1] === filtered[i]) {
                    merged[merged.length - 1] *= 2;
                    score += merged[merged.length - 1];
                } else {
                    merged.push(filtered[i]);
                }
            }

            // 3. Pad with zeros
            while (merged.length < SIZE) {
                merged.push(0);
            }

            return merged;
        };

        if (direction === 'left') {
            for (let r = 0; r < SIZE; r++) {
                const originalRow = boardState[r];
                const newRow = slideAndMerge(originalRow);
                if (JSON.stringify(originalRow) !== JSON.stringify(newRow)) {
                    moved = true;
                }
                boardState[r] = newRow;
            }
        } 
        else if (direction === 'right') {
            for (let r = 0; r < SIZE; r++) {
                const originalRow = boardState[r];
                // Reverse, slide left, reverse back
                const reversed = [...originalRow].reverse();
                const newRow = slideAndMerge(reversed);
                const finalRow = newRow.reverse();

                if (JSON.stringify(originalRow) !== JSON.stringify(finalRow)) {
                    moved = true;
                }
                boardState[r] = finalRow;
            }
        } 
        else if (direction === 'up') {
            // Transpose to treat columns as rows
            const transposed = Array(SIZE).fill(null).map(() => Array(SIZE).fill(0));
            for(let r=0; r<SIZE; r++) {
                for(let c=0; c<SIZE; c++) {
                    transposed[c][r] = boardState[r][c];
                }
            }

            for (let c = 0; c < SIZE; c++) {
                const originalCol = transposed[c]; // This is a row in the transposed matrix
                const newCol = slideAndMerge(originalCol);

                if (JSON.stringify(originalCol) !== JSON.stringify(newCol)) {
                    moved = true;
                }
                transposed[c] = newCol;
            }

            // Transpose back
            for(let r=0; r<SIZE; r++) {
                for(let c=0; c<SIZE; c++) {
                    boardState[r][c] = transposed[c][r];
                }
            }
        } 
        else if (direction === 'down') {
            // Transpose
            const transposed = Array(SIZE).fill(null).map(() => Array(SIZE).fill(0));
            for(let r=0; r<SIZE; r++) {
                for(let c=0; c<SIZE; c++) {
                    transposed[c][r] = boardState[r][c];
                }
            }

            for (let c = 0; c < SIZE; c++) {
                const originalCol = transposed[c];
                // Reverse, slide left, reverse back logic applied to column
                const reversed = [...originalCol].reverse();
                const newCol = slideAndMerge(reversed);
                const finalCol = newCol.reverse();

                if (JSON.stringify(originalCol) !== JSON.stringify(finalCol)) {
                    moved = true;
                }
                transposed[c] = finalCol;
            }

            // Transpose back
            for(let r=0; r<SIZE; r++) {
                for(let c=0; c<SIZE; c++) {
                    boardState[r][c] = transposed[c][r];
                }
            }
        }

        return moved;
    }

    // Start the game on load
    init();

})();
</script>
</body>
</html>
